import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input (could come from a form submission)
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handling user input with encoding
        String encodedUserInput = Encode.forHtml(userInput);
        String output = "<p>Welcome, " + encodedUserInput + "</p>";

        // Print the output to the console or web page
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();
            System.out.println("Output written to output.html");
        } catch (IOException e) {
            System.err.println("Error writing output: " + e.getMessage());
        }
    }
}

